from dataclasses import dataclass, field
from enum import Enum
from typing import Optional

class TurnState(str, Enum):
    ENTRY      = "entry"        # turn 1, no prior context
    MID        = "mid"          # 2-N turns, context accumulated
    CORRECTION = "correction"   # user corrects a previous turn
    ESCALATION = "escalation"   # AI signals inability to resolve
    COMPLETE   = "complete"     # all slots filled and confirmed
    ABANDONED  = "abandoned"    # session timed out or user left

@dataclass
class SlotSpec:
    name:     str
    required: bool = True
    filled:   bool = False   # True in AI CONTEXT if already collected

@dataclass
class AIContext:
    """Snapshot of conversational state at the point this story applies."""
    turn_state:      TurnState
    turn_index:      int              # 0 = entry
    slots:           list[SlotSpec]   # which slots are filled/unfilled
    confidence_min:  float = 0.0      # minimum model confidence for happy path
    memory_scope:    str  = "session" # "none" | "session" | "persistent"
    active_entities: list[str] = field(default_factory=list)  # names/IDs in context

    def unfilled_required_slots(self) -> list[str]:
        return [s.name for s in self.slots if s.required and not s.filled]

    def is_ready_to_act(self) -> bool:
        return len(self.unfilled_required_slots()) == 0

@dataclass
class FailPath:
    trigger:  str   # what caused the failure
    response: str   # what the AI should do
    max_turns: int  # how many turns before escalating

@dataclass
class ConversationalJobStory:
    story_id:     str
    situation:    str   # WHEN
    outcome:      str   # I WANT TO
    motivation:   str   # SO I CAN
    ai_context:   AIContext
    fail_path:    FailPath
    tags:         list[str] = field(default_factory=list)

    def is_entry_story(self) -> bool:
        return self.ai_context.turn_state == TurnState.ENTRY

    def requires_clarification(self) -> bool:
        return len(self.ai_context.unfilled_required_slots()) > 0

    def gherkin_title(self) -> str:
        return (
            f"WHEN {self.situation}\n"
            f"I WANT TO {self.outcome}\n"
            f"SO I CAN {self.motivation}\n"
            f"[turn={self.ai_context.turn_state.value}]"
        )

from dataclasses import dataclass, field

@dataclass
class DialogueNode:
    node_id:       str
    prompt:        str
    expected_intents: list[str]
    slot_to_fill:  str | None
    story_ids:     list[str]       # job stories that exercise this node
    next_on_fill:  str | None      # node_id if slot filled
    next_on_fail:  str | None      # node_id on fail-path

@dataclass
class DialogueFlow:
    flow_id:  str
    nodes:    list[DialogueNode]

    def stories_without_node(self, all_story_ids: list[str]) -> list[str]:
        """Find story IDs with no corresponding dialogue node."""
        covered = {sid for node in self.nodes for sid in node.story_ids}
        return [sid for sid in all_story_ids if sid not in covered]

    def nodes_without_story(self) -> list[DialogueNode]:
        """Find dialogue nodes with no associated job story (untested paths)."""
        return [n for n in self.nodes if not n.story_ids]

def coverage_report(
    stories: list["ConversationalJobStory"],
    flow:    "DialogueFlow",
) -> dict:
    story_ids = [s.story_id for s in stories]
    uncovered_stories  = flow.stories_without_node(story_ids)
    untested_nodes     = flow.nodes_without_story()

    state_counts = {}
    for s in stories:
        key = s.ai_context.turn_state.value
        state_counts[key] = state_counts.get(key, 0) + 1

    return {
        "total_stories":        len(stories),
        "state_distribution":   state_counts,
        "uncovered_in_flow":    uncovered_stories,  # stories with no dialogue node
        "untested_nodes":       [n.node_id for n in untested_nodes],
        "fail_path_coverage":   sum(1 for s in stories if s.fail_path.trigger) / max(len(stories),1),
    }
